// Classify Linear issue changes and normalize to Laya event format.

const TWO_MINUTES_MS = 150000; // 2.5 min to match poll window
const now = Date.now();

const input = $input.first().json;
const issues = (input.data && input.data.issues && input.data.issues.nodes) || [];

const results = [];

for (const issue of issues) {
  const createdAt = new Date(issue.createdAt).getTime();
  const updatedAt = new Date(issue.updatedAt).getTime();
  const isNew = (now - createdAt) < TWO_MINUTES_MS;

  // Parse recent history entries
  const history = (issue.history && issue.history.nodes) || [];
  const recentHistory = history.filter(h => (now - new Date(h.createdAt).getTime()) < TWO_MINUTES_MS);

  // Parse recent comments
  const comments = (issue.comments && issue.comments.nodes) || [];
  const recentComments = comments.filter(c => (now - new Date(c.createdAt).getTime()) < TWO_MINUTES_MS);

  // --- Classify change type ---
  let rawEventType = 'issue_updated';
  let body = '';
  let changeType = 'generic_update';
  let actorName = (issue.creator && issue.creator.displayName) || (issue.creator && issue.creator.name) || 'Unknown';
  let actorEmail = (issue.creator && issue.creator.email) || '';
  let actorHandle = (issue.creator && issue.creator.name) || '';

  if (isNew) {
    rawEventType = 'issue_created';
    changeType = 'created';
    body = issue.description || issue.title || '';

  } else {
    // Check history for status changes, reassignments, priority changes
    let statusChange = null;
    let assigneeChange = null;
    let priorityChange = null;

    for (const entry of recentHistory) {
      if (entry.fromState && entry.toState) {
        statusChange = entry;
      }
      if (entry.fromAssignee || entry.toAssignee) {
        assigneeChange = entry;
      }
      if (entry.fromPriority !== undefined && entry.fromPriority !== null &&
          entry.toPriority !== undefined && entry.toPriority !== null &&
          entry.fromPriority !== entry.toPriority) {
        priorityChange = entry;
      }
    }

    if (statusChange) {
      const fromName = statusChange.fromState.name;
      const toName = statusChange.toState.name;
      const toType = (statusChange.toState.type || '').toLowerCase();
      const fromType = (statusChange.fromState.type || '').toLowerCase();

      if ((toType === 'completed' || toType === 'canceled') && fromType !== 'completed' && fromType !== 'canceled') {
        rawEventType = 'issue_resolved';
        changeType = 'resolved';
        body = 'Issue ' + toName.toLowerCase() + ': ' + fromName + ' → ' + toName + '.';
      } else if ((fromType === 'completed' || fromType === 'canceled') && toType !== 'completed' && toType !== 'canceled') {
        rawEventType = 'issue_reopened';
        changeType = 'reopened';
        body = 'Issue reopened: ' + fromName + ' → ' + toName + '.';
      } else {
        rawEventType = 'issue_status_changed';
        changeType = 'status_changed';
        body = 'Status changed: ' + fromName + ' → ' + toName + '.';
      }

      if (statusChange.actor) {
        actorName = statusChange.actor.displayName || statusChange.actor.name || actorName;
        actorEmail = statusChange.actor.email || actorEmail;
        actorHandle = statusChange.actor.name || actorHandle;
      }

    } else if (assigneeChange) {
      rawEventType = 'issue_assigned';
      changeType = 'assigned';
      const from = (assigneeChange.fromAssignee && assigneeChange.fromAssignee.name) || 'Unassigned';
      const to = (assigneeChange.toAssignee && assigneeChange.toAssignee.name) || 'Unassigned';
      body = 'Assignee changed: ' + from + ' → ' + to + '.';

      if (assigneeChange.actor) {
        actorName = assigneeChange.actor.displayName || assigneeChange.actor.name || actorName;
        actorEmail = assigneeChange.actor.email || actorEmail;
        actorHandle = assigneeChange.actor.name || actorHandle;
      }

    } else if (priorityChange) {
      rawEventType = 'issue_priority_changed';
      changeType = 'priority_changed';
      const priorityLabels = ['No priority', 'Urgent', 'High', 'Medium', 'Low'];
      const fromLabel = priorityLabels[priorityChange.fromPriority] || String(priorityChange.fromPriority);
      const toLabel = priorityLabels[priorityChange.toPriority] || String(priorityChange.toPriority);
      body = 'Priority changed: ' + fromLabel + ' → ' + toLabel + '.';

      if (priorityChange.actor) {
        actorName = priorityChange.actor.displayName || priorityChange.actor.name || actorName;
        actorEmail = priorityChange.actor.email || actorEmail;
        actorHandle = priorityChange.actor.name || actorHandle;
      }

    } else if (recentComments.length > 0) {
      const latest = recentComments[recentComments.length - 1];
      rawEventType = 'issue_commented';
      changeType = 'commented';
      const commenterName = (latest.user && (latest.user.displayName || latest.user.name)) || 'Unknown';
      body = 'New comment from ' + commenterName + ':\n' + (latest.body || '');

      if (latest.user) {
        actorName = latest.user.displayName || latest.user.name || actorName;
        actorEmail = latest.user.email || actorEmail;
        actorHandle = latest.user.name || actorHandle;
      }

    } else {
      // Generic update — no specific change detected in poll window
      changeType = 'generic_update';
      body = 'Issue updated. Current status: ' + ((issue.state && issue.state.name) || 'Unknown') + '.';
    }
  }

  const epoch = new Date(issue.updatedAt || Date.now()).getTime();
  const teamKey = (issue.team && issue.team.key) || '';
  const teamId = (issue.team && issue.team.id) || '';
  const labels = (issue.labels && issue.labels.nodes) ? issue.labels.nodes.map(function(l) { return l.name; }) : [];

  results.push({
    json: {
      event_id: 'evt_linear_' + issue.id + '_' + epoch,
      timestamp: issue.updatedAt || new Date().toISOString(),
      source: {
        platform: 'linear',
        connection_id: $workflow.id,
        raw_event_type: rawEventType
      },
      actor: {
        name: actorName,
        email: actorEmail,
        platform_handle: actorHandle
      },
      subject: {
        type: 'ticket',
        id: issue.identifier || '',
        title: issue.title || '',
        url: issue.url || ''
      },
      content: {
        body: body,
        attachments: [],
        metadata: {
          linear_team: teamKey,
          linear_team_id: teamId,
          linear_labels: labels,
          linear_priority: issue.priorityLabel || null,
          linear_status: (issue.state && issue.state.name) || null,
          linear_status_type: (issue.state && issue.state.type) || null,
          linear_assignee: (issue.assignee && issue.assignee.email) || null,
          linear_assignee_name: (issue.assignee && issue.assignee.displayName) || null,
          linear_change_type: changeType,
          linear_description: issue.description || '',
          participants: [
            issue.creator ? { role: 'creator', name: (issue.creator.displayName || issue.creator.name || ''), email: issue.creator.email || '', handle: issue.creator.name || '' } : null,
            issue.assignee ? { role: 'assignee', name: (issue.assignee.displayName || issue.assignee.name || ''), email: issue.assignee.email || '', handle: issue.assignee.name || '' } : null
          ].filter(Boolean)
        }
      }
    }
  });
}

return results;
